import React, { useEffect, useRef, useState } from 'react'
import { Upload, X, CheckCircle, Sparkle, Warning } from '@phosphor-icons/react'
import { AnimatePresence, motion } from 'framer-motion'
import { scanCompleteInvoiceFiles } from '../services/enhancedReceiptAI'
import type { ScannedInvoiceData } from '../types'

interface ReceiptScannerProps {
  isOpen: boolean
  onClose: () => void
  onScanComplete: (data: ScannedInvoiceData) => void
  type: 'sale' | 'purchase' | 'expense'
}

type ScannedItem = ScannedInvoiceData['items'][number]

const round2 = (value: number) =>
  Math.round((Number(value || 0) + Number.EPSILON) * 100) / 100

const resolveItemTaxableBase = (item: ScannedItem) => {
  const quantity = Math.max(0, Number(item.quantity || 0))
  const rate = Math.max(0, Number(item.rate || 0))
  const amount = Math.max(0, Number(item.amount || 0))
  const explicitTaxable = Math.max(0, Number(item.taxableValue || 0))
  const qtyRateBase = round2(quantity * rate)

  if (amount > 0 && qtyRateBase > 0 && Math.abs(amount - qtyRateBase) <= Math.max(2, amount * 0.03)) {
    return amount
  }

  if (amount > 0 && explicitTaxable > 0 && Math.abs(amount - explicitTaxable) <= Math.max(2, amount * 0.03)) {
    return amount
  }

  if (amount > 0 && explicitTaxable > amount * 1.15) {
    return amount
  }

  if (qtyRateBase > 0 && explicitTaxable > qtyRateBase * 1.15) {
    return qtyRateBase
  }

  return explicitTaxable || amount || qtyRateBase
}

const normalizeScannedText = (value?: string) => {
  const text = String(value || '').trim()
  if (!text) return ''
  const upper = text.toUpperCase()
  if (['EXP', 'HSN', 'BATCH', 'MFR', 'MATH', 'GSTIN'].includes(upper)) return ''
  return text
}

const formatCurrency = (value: number) =>
  `Rs ${Number(value || 0).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`

const readFilesAsDataUrls = (files: File[]): Promise<string[]> =>
  Promise.all(
    files.map(
      file =>
        new Promise<string>((resolve, reject) => {
          const reader = new FileReader()
          reader.onload = event => resolve(String(event.target?.result || ''))
          reader.onerror = () => reject(new Error(`Failed to read ${file.name}`))
          reader.readAsDataURL(file)
        })
    )
  )

const getScannedItemIssues = (item: ScannedItem) => {
  const issues: string[] = []
  const batchText = String(item.batchNo || '').trim().toUpperCase()
  const expiryText = String(item.expiryDate || '').trim().toUpperCase()
  const hsnText = String(item.hsnCode || '').trim().toUpperCase()
  const qty = Math.max(0, Number(item.quantity) || 0)
  const rate = Math.max(0, Number(item.rate) || 0)
  const amount = Math.max(0, Number(item.amount) || 0)
  const discountAmount = Math.max(0, Number(item.discountAmount || 0))
  const taxAmount = Math.max(
    0,
    Number(item.gstAmount || 0) ||
      Number(item.cgstAmount || 0) + Number(item.sgstAmount || 0) + Number(item.igstAmount || 0)
  )
  const expectedAmount = round2((qty * rate) - discountAmount + taxAmount)
  const delta = Math.abs(expectedAmount - amount)

  if (!item.description?.trim()) issues.push('Name')
  if (!batchText || batchText === 'BATCH') issues.push('Batch')
  if (qty <= 0) issues.push('Qty')
  if (rate <= 0) issues.push('Rate')
  if (amount <= 0) issues.push('Amount')
  return issues
}

const summarizeScannedData = (data: ScannedInvoiceData) => {
  const itemsSubtotal = round2(data.items.reduce((sum, item) => sum + Math.max(0, Number(item.amount || 0)), 0))
  const itemsTaxTotal = round2(
    data.items.reduce((sum, item) => {
      const itemTax = Number(item.gstAmount || 0) ||
        Number(item.cgstAmount || 0) + Number(item.sgstAmount || 0) + Number(item.igstAmount || 0)
      return sum + Math.max(0, itemTax)
    }, 0)
  )
  const itemRateBasedTaxTotal = round2(
    data.items.reduce((sum, item) => {
      const taxableBase = resolveItemTaxableBase(item)
      const gstRate = Math.max(0, Number(item.gstRate || 0))
      if (taxableBase <= 0 || gstRate <= 0) return sum
      return sum + round2((taxableBase * gstRate) / 100)
    }, 0)
  )
  const explicitSubtotal = round2(Number(data.subtotal || 0))
  const explicitTaxable = round2(Number(data.taxableValue || 0))
  const explicitDiscount = round2(Number(data.discountAmount || 0))
  const explicitRoundOff = round2(Number(data.roundOff || 0))
  const explicitGrandTotal = round2(Number(data.grandTotal || 0))
  const taxFromBreakdown = round2(
    Number(data.totalTaxAmount || 0) ||
      Number(data.cgstAmount || 0) + Number(data.sgstAmount || 0) + Number(data.igstAmount || 0)
  )
  const derivedTaxFromGrandMath =
    explicitGrandTotal > 0 && explicitSubtotal > 0
      ? round2(Math.max(0, explicitGrandTotal - explicitSubtotal + explicitDiscount - explicitRoundOff))
      : 0
  const hasExplicitTaxBreakdown =
    taxFromBreakdown > 0 ||
    Number(data.cgstAmount || 0) > 0 ||
    Number(data.sgstAmount || 0) > 0 ||
    Number(data.igstAmount || 0) > 0
  const derivedTaxMatchesRateBased =
    derivedTaxFromGrandMath > 0 &&
    itemRateBasedTaxTotal > 0 &&
    Math.abs(derivedTaxFromGrandMath - itemRateBasedTaxTotal) <= Math.max(3, itemRateBasedTaxTotal * 0.12)
  const explicitBreakdownLooksSuspicious =
    hasExplicitTaxBreakdown &&
    derivedTaxFromGrandMath > 0 &&
    Math.abs(derivedTaxFromGrandMath - taxFromBreakdown) >= Math.max(5, derivedTaxFromGrandMath * 0.18)
  const derivedTaxLooksReasonable =
    derivedTaxFromGrandMath > 0 &&
    (
      !hasExplicitTaxBreakdown ||
      Math.abs(derivedTaxFromGrandMath - taxFromBreakdown) <= Math.max(2, taxFromBreakdown * 0.1)
    ) &&
    (
      (itemRateBasedTaxTotal <= 0 && itemsTaxTotal <= 0) ||
      Math.abs(derivedTaxFromGrandMath - (itemRateBasedTaxTotal || itemsTaxTotal)) <= Math.max(2, (itemRateBasedTaxTotal || itemsTaxTotal) * 0.15)
    )
  const rateBasedTaxLooksReasonable =
    itemRateBasedTaxTotal > 0 &&
    (
      itemsTaxTotal <= 0 ||
      Math.abs(itemRateBasedTaxTotal - itemsTaxTotal) >= Math.max(5, itemRateBasedTaxTotal * 0.25)
    )
  const explicitTaxLooksSuspicious =
    taxFromBreakdown > 0 &&
    itemRateBasedTaxTotal > 0 &&
    Math.abs(taxFromBreakdown - itemRateBasedTaxTotal) >= Math.max(8, itemRateBasedTaxTotal * 0.25)
  const grandMathTaxLooksBetter =
    derivedTaxFromGrandMath > 0 &&
    (
      itemRateBasedTaxTotal <= 0 ||
      Math.abs(derivedTaxFromGrandMath - itemRateBasedTaxTotal) <= Math.max(5, itemRateBasedTaxTotal * 0.15)
    ) &&
    (
      !hasExplicitTaxBreakdown ||
      Math.abs(derivedTaxFromGrandMath - taxFromBreakdown) >= Math.max(5, derivedTaxFromGrandMath * 0.2)
    )
  const totalTaxAmount = grandMathTaxLooksBetter
    ? derivedTaxFromGrandMath
    : derivedTaxMatchesRateBased && explicitBreakdownLooksSuspicious
      ? derivedTaxFromGrandMath
    : explicitTaxLooksSuspicious
      ? itemRateBasedTaxTotal
    : rateBasedTaxLooksReasonable
      ? itemRateBasedTaxTotal
      : hasExplicitTaxBreakdown
        ? taxFromBreakdown
        : derivedTaxLooksReasonable
          ? derivedTaxFromGrandMath
          : (itemRateBasedTaxTotal || itemsTaxTotal)

  const derivedTaxableFromGrand = explicitGrandTotal > 0
    ? round2(Math.max(0, explicitGrandTotal - totalTaxAmount - explicitRoundOff))
    : 0

  const summaryNoDiscountMathLooksValid =
    explicitSubtotal > 0 &&
    explicitGrandTotal > 0 &&
    Math.abs(round2(explicitSubtotal + totalTaxAmount + explicitRoundOff) - explicitGrandTotal) <=
      Math.max(2, explicitGrandTotal * 0.02)
  const summaryDiscountMathLooksValid =
    explicitDiscount > 0 &&
    explicitSubtotal > 0 &&
    explicitGrandTotal > 0 &&
    Math.abs(round2(explicitSubtotal - explicitDiscount + totalTaxAmount + explicitRoundOff) - explicitGrandTotal) <=
      Math.max(2, explicitGrandTotal * 0.02)
  const summaryMathLooksReliable = summaryNoDiscountMathLooksValid || summaryDiscountMathLooksValid
  const discountAmount = summaryNoDiscountMathLooksValid ? 0 : (summaryDiscountMathLooksValid ? explicitDiscount : 0)
  const trustedSubtotal = explicitSubtotal > 0
    ? (
      itemsSubtotal > 0 && Math.abs(explicitSubtotal - itemsSubtotal) <= Math.max(2, explicitSubtotal * 0.05)
        ? explicitSubtotal
        : explicitSubtotal
    )
    : itemsSubtotal
  const subtotalBasedTaxable = round2(Math.max(0, trustedSubtotal - discountAmount))
  const subtotalBasedGrand = round2(subtotalBasedTaxable + totalTaxAmount + explicitRoundOff)
  const subtotalMathLooksReliable =
    trustedSubtotal > 0 &&
    totalTaxAmount >= 0 &&
    (
      itemsSubtotal <= 0 ||
      Math.abs(trustedSubtotal - itemsSubtotal) <= Math.max(2, trustedSubtotal * 0.05)
    )
  const explicitGrandTotalLooksReliable =
    explicitGrandTotal > 0 &&
    Math.abs(explicitGrandTotal - subtotalBasedGrand) <= Math.max(2, subtotalBasedGrand * 0.03)

  const explicitTaxableLooksValid =
    explicitTaxable > 0 &&
    (
      (explicitGrandTotal > 0 && Math.abs(explicitTaxable - derivedTaxableFromGrand) <= Math.max(2, explicitGrandTotal * 0.03)) ||
      (trustedSubtotal > 0 && Math.abs(explicitTaxable - subtotalBasedTaxable) <= Math.max(2, trustedSubtotal * 0.05))
    )

  const taxableValue = summaryMathLooksReliable
    ? round2(Math.max(0, explicitSubtotal - discountAmount))
    : subtotalMathLooksReliable
    ? subtotalBasedTaxable
    : explicitTaxableLooksValid
      ? explicitTaxable
      : derivedTaxableFromGrand > 0
        ? derivedTaxableFromGrand
        : round2(Math.max(0, trustedSubtotal - discountAmount))

  const subtotal = summaryMathLooksReliable
    ? explicitSubtotal
    : trustedSubtotal > 0
    ? trustedSubtotal
    : round2(taxableValue + discountAmount)

  const computedGrandTotal = round2(taxableValue + totalTaxAmount + explicitRoundOff)
  const grandTotal = summaryMathLooksReliable
    ? explicitGrandTotal
    : subtotalMathLooksReliable
      ? subtotalBasedGrand
    : explicitGrandTotalLooksReliable
      ? explicitGrandTotal
      : computedGrandTotal

  const itemCgstAmount = round2(data.items.reduce((sum, item) => sum + Math.max(0, Number(item.cgstAmount || 0)), 0))
  const itemSgstAmount = round2(data.items.reduce((sum, item) => sum + Math.max(0, Number(item.sgstAmount || 0)), 0))
  const itemIgstAmount = round2(data.items.reduce((sum, item) => sum + Math.max(0, Number(item.igstAmount || 0)), 0))
  const hasItemTaxBreakdown = itemCgstAmount > 0 || itemSgstAmount > 0 || itemIgstAmount > 0
  const itemIgstRateBasedAmount = round2(
    data.items.reduce((sum, item) => {
      const taxableBase = resolveItemTaxableBase(item)
      const gstRate = Math.max(0, Number(item.gstRate || 0))
      const igstAmount = Math.max(0, Number(item.igstAmount || 0))
      if (taxableBase <= 0 || gstRate <= 0 || igstAmount <= 0) return sum
      return sum + round2((taxableBase * gstRate) / 100)
    }, 0)
  )
  const rateBasedIgstAmount = itemIgstRateBasedAmount > 0 ? itemIgstRateBasedAmount : 0
  const rateBasedCgstAmount = rateBasedIgstAmount > 0 ? 0 : round2(totalTaxAmount / 2)
  const rateBasedSgstAmount = rateBasedIgstAmount > 0 ? 0 : round2(totalTaxAmount - rateBasedCgstAmount)

  const explicitCgstAmount = round2(Number(data.cgstAmount || 0))
  const explicitSgstAmount = round2(Number(data.sgstAmount || 0))
  const explicitIgstAmount = round2(Number(data.igstAmount || 0))
  const explicitBreakdownTotal = round2(explicitCgstAmount + explicitSgstAmount + explicitIgstAmount)
  const explicitBreakdownLooksReasonable =
    explicitBreakdownTotal > 0 &&
    Math.abs(explicitBreakdownTotal - totalTaxAmount) <= Math.max(2, totalTaxAmount * 0.1)

  const derivedCgstAmount = explicitBreakdownLooksReasonable
    ? explicitCgstAmount
    : explicitTaxLooksSuspicious
      ? rateBasedCgstAmount
    : rateBasedTaxLooksReasonable
      ? rateBasedCgstAmount
    : hasItemTaxBreakdown
      ? itemCgstAmount
      : explicitIgstAmount > 0
        ? 0
        : round2(totalTaxAmount / 2)
  const derivedSgstAmount = explicitBreakdownLooksReasonable
    ? explicitSgstAmount
    : explicitTaxLooksSuspicious
      ? rateBasedSgstAmount
    : rateBasedTaxLooksReasonable
      ? rateBasedSgstAmount
    : hasItemTaxBreakdown
      ? itemSgstAmount
      : explicitIgstAmount > 0
        ? 0
        : round2(totalTaxAmount - derivedCgstAmount)
  const derivedIgstAmount = explicitBreakdownLooksReasonable
    ? explicitIgstAmount
    : explicitTaxLooksSuspicious
      ? rateBasedIgstAmount
    : rateBasedTaxLooksReasonable
      ? rateBasedIgstAmount
    : hasItemTaxBreakdown
      ? itemIgstAmount
      : 0

  const derivedCgstRate = derivedCgstAmount > 0 && taxableValue > 0
    ? round2((derivedCgstAmount / taxableValue) * 100)
    : round2(Number(data.cgstRate || 0))
  const derivedSgstRate = derivedSgstAmount > 0 && taxableValue > 0
    ? round2((derivedSgstAmount / taxableValue) * 100)
    : round2(Number(data.sgstRate || 0))
  const derivedIgstRate = derivedIgstAmount > 0 && taxableValue > 0
    ? round2((derivedIgstAmount / taxableValue) * 100)
    : round2(Number(data.igstRate || 0))

  return {
    subtotal,
    totalTaxAmount,
    discountAmount,
    taxableValue,
    grandTotal,
    cgstAmount: derivedCgstAmount,
    sgstAmount: derivedSgstAmount,
    igstAmount: derivedIgstAmount,
    cgstRate: derivedCgstRate,
    sgstRate: derivedSgstRate,
    igstRate: derivedIgstRate,
  }
}

const normalizeScanResult = (data: ScannedInvoiceData): ScannedInvoiceData => {
  const normalizedItems = (data.items || []).map(item => ({
    ...item,
    description: normalizeScannedText(item.description),
    manufacturer: normalizeScannedText(item.manufacturer),
    batchNo: normalizeScannedText(item.batchNo),
    expiryDate: normalizeScannedText(item.expiryDate),
    packageType: normalizeScannedText(item.packageType),
    hsnCode: normalizeScannedText(item.hsnCode),
    unit: normalizeScannedText(item.unit) || 'PCS',
  }))

  const normalizedData: ScannedInvoiceData = {
    ...data,
    vendor: {
      ...data.vendor,
      name: normalizeScannedText(data.vendor?.name),
      gstin: normalizeScannedText(data.vendor?.gstin),
      phone: normalizeScannedText(data.vendor?.phone),
      address: normalizeScannedText(data.vendor?.address),
    },
    buyer: data.buyer
      ? {
          ...data.buyer,
          name: normalizeScannedText(data.buyer?.name),
          gstin: normalizeScannedText(data.buyer?.gstin),
          address: normalizeScannedText(data.buyer?.address),
        }
      : undefined,
    invoiceNumber: normalizeScannedText(data.invoiceNumber),
    invoiceDate: normalizeScannedText(data.invoiceDate),
    vehicleNumber: normalizeScannedText(data.vehicleNumber),
    items: normalizedItems,
  }

  const repairedSummary = summarizeScannedData(normalizedData)

  return {
    ...normalizedData,
    subtotal: repairedSummary.subtotal,
    taxableValue: repairedSummary.taxableValue,
    totalTaxAmount: repairedSummary.totalTaxAmount,
    cgstAmount: repairedSummary.cgstAmount,
    sgstAmount: repairedSummary.sgstAmount,
    igstAmount: repairedSummary.igstAmount,
    cgstRate: repairedSummary.cgstRate,
    sgstRate: repairedSummary.sgstRate,
    igstRate: repairedSummary.igstRate,
    discountAmount: repairedSummary.discountAmount,
    grandTotal: repairedSummary.grandTotal,
  }
}

const ReceiptScanner: React.FC<ReceiptScannerProps> = ({ isOpen, onClose, onScanComplete, type }) => {
  const [isScanning, setIsScanning] = useState(false)
  const [selectedFiles, setSelectedFiles] = useState<File[]>([])
  const [previewImages, setPreviewImages] = useState<string[]>([])
  const [activePreviewIndex, setActivePreviewIndex] = useState(0)
  const [scanResult, setScanResult] = useState<ScannedInvoiceData | null>(null)
  const [editableScanResult, setEditableScanResult] = useState<ScannedInvoiceData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [fileSelectionMode, setFileSelectionMode] = useState<'replace' | 'append'>('replace')
  const fileInputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    if (!isOpen) return

    setSelectedFiles([])
    setPreviewImages([])
    setActivePreviewIndex(0)
    setScanResult(null)
    setEditableScanResult(null)
    setIsScanning(false)
    setError(null)
    setFileSelectionMode('replace')
    if (fileInputRef.current) fileInputRef.current.value = ''
  }, [isOpen])

  const openFilePicker = (mode: 'replace' | 'append' = 'replace') => {
    setFileSelectionMode(mode)
    if (fileInputRef.current) {
      fileInputRef.current.value = ''
      fileInputRef.current.click()
    }
  }

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const incomingFiles = Array.from(event.target.files || [])
    if (!incomingFiles.length) return

    const files = fileSelectionMode === 'append'
      ? [...selectedFiles, ...incomingFiles]
      : incomingFiles

    if (files.some(file => !file.type.startsWith('image/'))) {
      setError('Please upload image files only (JPG, PNG, WebP, etc.)')
      return
    }

    if (files.some(file => file.size > 10 * 1024 * 1024)) {
      setError('Each file size must be less than 10MB')
      return
    }

    setError(null)
    setSelectedFiles(files)
    setActivePreviewIndex(0)
    setIsScanning(true)

    try {
      const previews = await readFilesAsDataUrls(files)
      setPreviewImages(previews)

      const scannedData = normalizeScanResult(await scanCompleteInvoiceFiles(files))
      setScanResult(scannedData)
      setEditableScanResult(scannedData)
    } catch (err: any) {
      console.error('Scanning error:', err)
      const firebaseCode = err?.code ? ` (${err.code})` : ''
      const firebaseDetails = err?.details ? `\nDetails: ${err.details}` : ''
      const errorMessage = err?.message
        ? `${err.message}${firebaseCode}${firebaseDetails}`
        : 'Failed to scan invoice. Please try again.'
      setError(errorMessage)
      setSelectedFiles([])
      setPreviewImages([])
      setActivePreviewIndex(0)
      setScanResult(null)
      setEditableScanResult(null)
    } finally {
      setIsScanning(false)
    }
  }

  const handleReset = () => {
    setSelectedFiles([])
    setPreviewImages([])
    setActivePreviewIndex(0)
    setScanResult(null)
    setEditableScanResult(null)
    setIsScanning(false)
    setError(null)
    if (fileInputRef.current) fileInputRef.current.value = ''
  }

  const handleClose = () => {
    handleReset()
    onClose()
  }

  const handleConfirm = () => {
    if (!editableScanResult) return

    const confirmedSummary = summarizeScannedData(editableScanResult)
    const confirmedResult: ScannedInvoiceData = {
      ...editableScanResult,
      subtotal: confirmedSummary.subtotal,
      taxableValue: confirmedSummary.taxableValue,
      totalTaxAmount: confirmedSummary.totalTaxAmount,
      cgstAmount: confirmedSummary.cgstAmount,
      sgstAmount: confirmedSummary.sgstAmount,
      igstAmount: confirmedSummary.igstAmount,
      cgstRate: confirmedSummary.cgstRate,
      sgstRate: confirmedSummary.sgstRate,
      igstRate: confirmedSummary.igstRate,
      discountAmount: confirmedSummary.discountAmount,
      grandTotal: confirmedSummary.grandTotal,
    }

    onScanComplete(confirmedResult)
    handleReset()
    onClose()
  }

  const updateEditableResult = (updater: (current: ScannedInvoiceData) => ScannedInvoiceData) => {
    setEditableScanResult(current => (current ? updater(current) : current))
  }

  const handleHeaderChange = (section: 'vendor' | 'buyer', field: string, value: string) => {
    updateEditableResult(current => ({
      ...current,
      [section]: {
        ...(current[section] || { name: '' }),
        [field]: value,
      },
    }))
  }

  const handleRootFieldChange = (field: keyof ScannedInvoiceData, value: string) => {
    updateEditableResult(current => ({
      ...current,
      [field]: value,
    }))
  }

  const handleItemFieldChange = (index: number, field: keyof ScannedItem, value: string) => {
    updateEditableResult(current => ({
      ...current,
      items: current.items.map((item, itemIndex) => {
        if (itemIndex !== index) return item

        const numericFields: Array<keyof ScannedItem> = [
          'quantity',
          'rate',
          'mrp',
          'discountPercent',
          'discountAmount',
          'taxableValue',
          'gstRate',
          'gstAmount',
          'cgstAmount',
          'sgstAmount',
          'igstAmount',
          'amount',
        ]

        return {
          ...item,
          [field]: numericFields.includes(field) ? Math.max(0, Number(value) || 0) : value,
        }
      }),
    }))
  }

  if (!isOpen) return null

  const activeResult = editableScanResult || scanResult
  const discountLabel = activeResult?.discountPercent ? ` (${activeResult.discountPercent}%)` : ''
  const hasPreviews = previewImages.length > 0
  const activePreview = previewImages[activePreviewIndex] || previewImages[0]
  const reviewedSummary = activeResult ? summarizeScannedData(activeResult) : null
  const flaggedItems = activeResult
    ? activeResult.items
        .map((item, index) => ({
          index,
          description: item.description || `Item ${index + 1}`,
          issues: getScannedItemIssues(item),
        }))
        .filter(entry => entry.issues.length > 0)
    : []

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-start justify-center overflow-y-auto p-4">
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={handleClose}
          className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        />

        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative my-4 flex w-full max-w-7xl flex-col overflow-hidden rounded-2xl bg-white shadow-2xl"
        >
          <div className="flex items-center justify-between border-b border-slate-200 bg-gradient-to-r from-blue-50 to-indigo-50 px-6 py-4">
            <div className="flex items-center gap-3">
              <div className="rounded-xl bg-gradient-to-br from-blue-500 to-indigo-500 p-2">
                <Sparkle size={20} weight="duotone" className="text-white" />
              </div>
              <div>
                <h2 className="text-lg font-bold text-slate-900">AI Receipt Scanner</h2>
                <p className="text-xs text-slate-600">Scan, review, and then add {type} details</p>
              </div>
            </div>
            <button onClick={handleClose} className="rounded-lg p-2 transition-colors hover:bg-slate-200">
              <X size={20} className="text-slate-600" />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6">
            {!hasPreviews ? (
              <div className="space-y-4">
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/*"
                  multiple
                  onChange={handleFileSelect}
                  className="hidden"
                />

                <button
                  onClick={() => openFilePicker('replace')}
                  className="group w-full rounded-xl border-2 border-dashed border-slate-300 p-8 transition-all hover:border-blue-400 hover:bg-blue-50/50"
                >
                  <div className="flex flex-col items-center gap-3">
                    <div className="rounded-full bg-blue-100 p-4 transition-colors group-hover:bg-blue-200">
                      <Upload size={32} weight="duotone" className="text-blue-600" />
                    </div>
                    <div className="text-center">
                      <p className="font-semibold text-slate-900">Upload Invoice/Receipt Images</p>
                      <p className="mt-1 text-sm text-slate-500">Click and select one, two, or any number of bill pages together</p>
                      <p className="mt-1 text-xs text-slate-400">JPG, PNG, WebP (each max 10MB). Multi-page scan auto fills the bill.</p>
                    </div>
                  </div>
                </button>

                {error && (
                  <div className="flex items-start gap-3 rounded-lg border border-red-200 bg-red-50 p-4">
                    <Warning size={20} weight="duotone" className="mt-0.5 flex-shrink-0 text-red-600" />
                    <div>
                      <p className="text-sm font-semibold text-red-900">Upload Error</p>
                      <p className="mt-1 whitespace-pre-line text-xs text-red-700">{error}</p>
                    </div>
                  </div>
                )}

                <div className="mt-6 grid grid-cols-3 gap-3">
                  <div className="rounded-lg border border-green-200 bg-green-50 p-3">
                    <CheckCircle size={16} weight="duotone" className="mb-1 text-green-600" />
                    <p className="text-xs font-semibold text-green-900">Header First</p>
                    <p className="text-[10px] text-green-700">Safe Autofill</p>
                  </div>
                  <div className="rounded-lg border border-blue-200 bg-blue-50 p-3">
                    <CheckCircle size={16} weight="duotone" className="mb-1 text-blue-600" />
                    <p className="text-xs font-semibold text-blue-900">Review Rows</p>
                    <p className="text-[10px] text-blue-700">Edit Before Apply</p>
                  </div>
                  <div className="rounded-lg border border-purple-200 bg-purple-50 p-3">
                    <CheckCircle size={16} weight="duotone" className="mb-1 text-purple-600" />
                    <p className="text-xs font-semibold text-purple-900">Business Safe</p>
                    <p className="text-[10px] text-purple-700">Avoid Wrong Save</p>
                  </div>
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 gap-6 xl:grid-cols-[380px_minmax(0,1fr)] xl:items-start">
                <div className="space-y-3 xl:sticky xl:top-0">
                  <div className="flex items-center justify-between">
                    <h3 className="font-semibold text-slate-900">Receipt Images</h3>
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-medium text-slate-500">
                        {selectedFiles.length} page{selectedFiles.length === 1 ? '' : 's'}
                      </span>
                      <button
                        type="button"
                        onClick={() => openFilePicker('append')}
                        className="rounded-lg border border-blue-200 bg-blue-50 px-2.5 py-1 text-[11px] font-semibold text-blue-700 hover:bg-blue-100"
                      >
                        Add More Pages
                      </button>
                      <button
                        type="button"
                        onClick={() => openFilePicker('replace')}
                        className="rounded-lg border border-slate-200 bg-white px-2.5 py-1 text-[11px] font-semibold text-slate-700 hover:bg-slate-50"
                      >
                        Select Files
                      </button>
                    </div>
                  </div>
                  <div className="relative overflow-hidden rounded-lg border border-slate-200">
                    <img src={activePreview} alt="Receipt" className="h-auto w-full" />
                    {isScanning && (
                      <div className="absolute inset-0 flex items-center justify-center bg-blue-600/20 backdrop-blur-sm">
                        <div className="rounded-full bg-white p-4 shadow-lg">
                          <Sparkle size={24} weight="duotone" className="animate-pulse text-blue-600" />
                        </div>
                      </div>
                    )}
                  </div>

                  {previewImages.length > 1 && (
                    <div className="grid grid-cols-4 gap-2">
                      {previewImages.map((image, index) => (
                        <button
                          key={`${selectedFiles[index]?.name || 'preview'}-${index}`}
                          type="button"
                          onClick={() => setActivePreviewIndex(index)}
                          className={`overflow-hidden rounded-lg border-2 transition-colors ${
                            index === activePreviewIndex ? 'border-blue-500' : 'border-slate-200 hover:border-slate-300'
                          }`}
                        >
                          <img src={image} alt={`Receipt page ${index + 1}`} className="h-20 w-full object-cover" />
                        </button>
                      ))}
                    </div>
                  )}
                </div>

                <div className="min-h-0 space-y-4">
                  <h3 className="sticky top-0 bg-white pb-2 font-semibold text-slate-900">Review Extracted Data</h3>
                  {isScanning ? (
                    <div className="flex flex-col items-center justify-center py-12">
                      <div className="mb-4 h-12 w-12 animate-spin rounded-full border-4 border-blue-200 border-t-blue-600" />
                      <p className="text-sm text-slate-600">Scanning invoice...</p>
                      <p className="mt-1 text-xs text-slate-400">Combining all selected bill images with AI</p>
                    </div>
                  ) : error ? (
                    <div className="flex flex-col items-center justify-center py-12">
                      <Warning size={48} weight="duotone" className="mb-3 text-red-400" />
                      <p className="text-center text-sm text-red-600">{error}</p>
                    </div>
                  ) : activeResult ? (
                    <div className="space-y-4">
                      {flaggedItems.length > 0 && (
                        <div className="rounded-lg border border-amber-200 bg-amber-50 p-3">
                          <p className="text-xs font-semibold text-amber-900">Rows Need Review</p>
                          <p className="mt-1 text-xs text-amber-800">
                            {flaggedItems.length} row(s) still look suspicious. Fix item values here before adding them to Purchases.
                          </p>
                          <div className="mt-2 flex flex-wrap gap-2">
                            {flaggedItems.slice(0, 8).map(item => (
                              <span
                                key={`${item.description}-${item.index}`}
                                className="rounded-full bg-white px-2 py-1 text-[10px] font-medium text-amber-900"
                              >
                                Row {item.index + 1}: {item.description} [{item.issues.join(', ')}]
                              </span>
                            ))}
                          </div>
                        </div>
                      )}

                      <div className="grid gap-3 md:grid-cols-2">
                        <div className="rounded-lg border border-blue-200 bg-blue-50 p-3">
                          <p className="mb-2 text-xs font-semibold text-blue-900">Vendor/Supplier</p>
                          <input
                            value={activeResult.vendor.name}
                            onChange={event => handleHeaderChange('vendor', 'name', event.target.value)}
                            className="w-full rounded border border-blue-200 bg-white px-2 py-1 font-semibold text-slate-900"
                          />
                          <input
                            value={activeResult.vendor.gstin || ''}
                            onChange={event => handleHeaderChange('vendor', 'gstin', event.target.value)}
                            placeholder="GSTIN"
                            className="mt-2 w-full rounded border border-blue-200 bg-white px-2 py-1 text-xs text-slate-700"
                          />
                        </div>

                        {activeResult.buyer && (
                          <div className="rounded-lg border border-green-200 bg-green-50 p-3">
                            <p className="mb-2 text-xs font-semibold text-green-900">Buyer</p>
                            <input
                              value={activeResult.buyer.name || ''}
                              onChange={event => handleHeaderChange('buyer', 'name', event.target.value)}
                              className="w-full rounded border border-green-200 bg-white px-2 py-1 font-semibold text-slate-900"
                            />
                            <input
                              value={activeResult.buyer.gstin || ''}
                              onChange={event => handleHeaderChange('buyer', 'gstin', event.target.value)}
                              placeholder="GSTIN"
                              className="mt-2 w-full rounded border border-green-200 bg-white px-2 py-1 text-xs text-slate-700"
                            />
                          </div>
                        )}
                      </div>

                      <div className="grid gap-3 md:grid-cols-3">
                        <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
                          <p className="mb-1 text-xs text-slate-500">Invoice No</p>
                          <input
                            value={activeResult.invoiceNumber || ''}
                            onChange={event => handleRootFieldChange('invoiceNumber', event.target.value)}
                            className="w-full rounded border border-slate-200 bg-white px-2 py-1 font-semibold text-slate-900"
                          />
                        </div>
                        <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
                          <p className="mb-1 text-xs text-slate-500">Date</p>
                          <input
                            value={activeResult.invoiceDate || ''}
                            onChange={event => handleRootFieldChange('invoiceDate', event.target.value)}
                            className="w-full rounded border border-slate-200 bg-white px-2 py-1 font-semibold text-slate-900"
                          />
                        </div>
                        <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
                          <p className="mb-1 text-xs text-slate-500">Vehicle Number</p>
                          <input
                            value={activeResult.vehicleNumber || ''}
                            onChange={event => handleRootFieldChange('vehicleNumber', event.target.value)}
                            className="w-full rounded border border-slate-200 bg-white px-2 py-1 font-semibold text-slate-900"
                          />
                        </div>
                      </div>

                      <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
                        <p className="mb-2 text-xs text-slate-500">Items ({activeResult.items.length})</p>
                        <div className="overflow-x-auto rounded-lg border border-slate-200 bg-white">
                          <table className="min-w-[1400px] text-[11px]">
                            <thead className="bg-slate-100 text-slate-700">
                              <tr>
                                <th className="px-2 py-2 text-left font-semibold">Description</th>
                                <th className="px-2 py-2 text-left font-semibold">HSN</th>
                                <th className="px-2 py-2 text-right font-semibold">Qty</th>
                                <th className="px-2 py-2 text-left font-semibold">Unit</th>
                                <th className="px-2 py-2 text-right font-semibold">Rate</th>
                                <th className="px-2 py-2 text-right font-semibold">MRP</th>
                                <th className="px-2 py-2 text-right font-semibold">Dis%</th>
                                <th className="px-2 py-2 text-right font-semibold">GST%</th>
                                <th className="px-2 py-2 text-right font-semibold">Amount</th>
                              </tr>
                            </thead>
                            <tbody>
                              {activeResult.items.map((item, idx) => {
                                const rowIssues = getScannedItemIssues(item)

                                return (
                                  <tr
                                    key={idx}
                                    className={`border-t align-top ${
                                      rowIssues.length > 0 ? 'border-amber-200 bg-amber-50/60' : 'border-slate-100'
                                    }`}
                                  >
                                    <td className="px-2 py-2">
                                      <input
                                        value={item.description}
                                        onChange={event => handleItemFieldChange(idx, 'description', event.target.value)}
                                        className="w-64 rounded border border-slate-200 px-2 py-1 font-medium text-slate-900"
                                      />
                                      <div className="mt-2 grid grid-cols-1 gap-1">
                                        <input
                                          value={item.manufacturer || ''}
                                          onChange={event => handleItemFieldChange(idx, 'manufacturer', event.target.value)}
                                          placeholder="MFR"
                                          className="rounded border border-slate-200 px-2 py-1 text-[10px]"
                                        />
                                        <input
                                          value={item.batchNo || ''}
                                          onChange={event => handleItemFieldChange(idx, 'batchNo', event.target.value)}
                                          placeholder="Batch"
                                          className="rounded border border-slate-200 px-2 py-1 text-[10px]"
                                        />
                                        <input
                                          value={item.expiryDate || ''}
                                          onChange={event => handleItemFieldChange(idx, 'expiryDate', event.target.value)}
                                          placeholder="EXP"
                                          className="rounded border border-slate-200 px-2 py-1 text-[10px]"
                                        />
                                      </div>
                                      {rowIssues.length > 0 && (
                                        <div className="mt-2 flex flex-wrap gap-1">
                                          {rowIssues.map(issue => (
                                            <span
                                              key={`${idx}-${issue}`}
                                              className="rounded-full bg-amber-100 px-2 py-0.5 text-[9px] font-semibold text-amber-900"
                                            >
                                              {issue}
                                            </span>
                                          ))}
                                        </div>
                                      )}
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        value={item.hsnCode || ''}
                                        onChange={event => handleItemFieldChange(idx, 'hsnCode', event.target.value)}
                                        className="w-24 rounded border border-slate-200 px-2 py-1"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        type="number"
                                        min="0"
                                        step="1"
                                        value={item.quantity}
                                        onChange={event => handleItemFieldChange(idx, 'quantity', event.target.value)}
                                        className="w-20 rounded border border-slate-200 px-2 py-1 text-right"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        value={item.unit}
                                        onChange={event => handleItemFieldChange(idx, 'unit', event.target.value)}
                                        className="w-20 rounded border border-slate-200 px-2 py-1"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.rate}
                                        onChange={event => handleItemFieldChange(idx, 'rate', event.target.value)}
                                        className="w-24 rounded border border-slate-200 px-2 py-1 text-right"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.mrp || 0}
                                        onChange={event => handleItemFieldChange(idx, 'mrp', event.target.value)}
                                        className="w-24 rounded border border-slate-200 px-2 py-1 text-right"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={Number(item.discountPercent || 0)}
                                        onChange={event => handleItemFieldChange(idx, 'discountPercent', event.target.value)}
                                        className="w-20 rounded border border-slate-200 px-2 py-1 text-right"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={Number(item.gstRate || 0)}
                                        onChange={event => handleItemFieldChange(idx, 'gstRate', event.target.value)}
                                        className="w-20 rounded border border-slate-200 px-2 py-1 text-right"
                                      />
                                    </td>
                                    <td className="px-2 py-2">
                                      <input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={item.amount}
                                        onChange={event => handleItemFieldChange(idx, 'amount', event.target.value)}
                                        className="w-24 rounded border border-slate-200 px-2 py-1 text-right font-semibold"
                                      />
                                    </td>
                                  </tr>
                                )
                              })}
                            </tbody>
                          </table>
                        </div>
                      </div>

                      <div className="grid gap-3 lg:grid-cols-2">
                        <div className="rounded-lg border border-emerald-200 bg-emerald-50 p-3">
                          <p className="mb-2 text-xs font-semibold text-emerald-900">Bill Calculation</p>
                          <div className="space-y-1 text-sm">
                            <div className="flex justify-between">
                              <span className="text-slate-700">Subtotal</span>
                              <span className="font-semibold">{formatCurrency(reviewedSummary?.subtotal || 0)}</span>
                            </div>
                            {(reviewedSummary?.discountAmount || 0) > 0 && (
                              <div className="flex justify-between">
                                <span className="text-slate-700">Discount{discountLabel}</span>
                                <span className="font-semibold text-red-600">-{formatCurrency(reviewedSummary?.discountAmount || 0)}</span>
                              </div>
                            )}
                            <div className="flex justify-between">
                              <span className="text-slate-700">Taxable/Base</span>
                              <span className="font-semibold">{formatCurrency(reviewedSummary?.taxableValue || 0)}</span>
                            </div>
                            <div className="flex justify-between">
                              <span className="text-slate-700">GST Total</span>
                              <span className="font-semibold">{formatCurrency(reviewedSummary?.totalTaxAmount || 0)}</span>
                            </div>
                            {activeResult.roundOff !== 0 && (
                              <div className="flex justify-between text-xs">
                                <span className="text-slate-600">Round Off</span>
                                <span>{activeResult.roundOff > 0 ? '+' : ''}{formatCurrency(activeResult.roundOff)}</span>
                              </div>
                            )}
                            <div className="mt-2 rounded-md bg-white/70 px-3 py-2 text-xs text-emerald-900">
                              {formatCurrency(reviewedSummary?.taxableValue || 0)}
                              {` + GST ${formatCurrency(reviewedSummary?.totalTaxAmount || 0)}`}
                              {(reviewedSummary?.discountAmount || 0) > 0 ? ` - DIS ${formatCurrency(reviewedSummary?.discountAmount || 0)}` : ''}
                              {activeResult.roundOff !== 0 ? ` ${activeResult.roundOff > 0 ? '+' : '-'} Round ${formatCurrency(Math.abs(activeResult.roundOff))}` : ''}
                              {` = ${formatCurrency(reviewedSummary?.grandTotal || 0)}`}
                            </div>
                          </div>
                        </div>

                        <div className="rounded-lg border border-purple-200 bg-purple-50 p-3">
                          <p className="mb-2 text-xs font-semibold text-purple-900">Tax Breakdown</p>
                          <div className="space-y-1 text-sm">
                            <div className="flex justify-between">
                              <span className="text-slate-700">Taxable Value</span>
                              <span className="font-semibold">{formatCurrency(reviewedSummary?.taxableValue || 0)}</span>
                            </div>
                            {(reviewedSummary?.cgstAmount || 0) > 0 && (
                              <div className="flex justify-between">
                                <span className="text-slate-700">CGST ({reviewedSummary?.cgstRate || 0}%)</span>
                                <span className="font-semibold">{formatCurrency(reviewedSummary?.cgstAmount || 0)}</span>
                              </div>
                            )}
                            {(reviewedSummary?.sgstAmount || 0) > 0 && (
                              <div className="flex justify-between">
                                <span className="text-slate-700">SGST ({reviewedSummary?.sgstRate || 0}%)</span>
                                <span className="font-semibold">{formatCurrency(reviewedSummary?.sgstAmount || 0)}</span>
                              </div>
                            )}
                            {(reviewedSummary?.igstAmount || 0) > 0 && (
                              <div className="flex justify-between">
                                <span className="text-slate-700">IGST ({reviewedSummary?.igstRate || 0}%)</span>
                                <span className="font-semibold">{formatCurrency(reviewedSummary?.igstAmount || 0)}</span>
                              </div>
                            )}
                            <div className="flex justify-between border-t border-purple-200 pt-2">
                              <span className="font-bold text-purple-900">Grand Total</span>
                              <span className="font-bold text-purple-900">{formatCurrency(reviewedSummary?.grandTotal || 0)}</span>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ) : null}
                </div>
              </div>
            )}
          </div>

          {hasPreviews && !isScanning && activeResult && (
            <div className="flex gap-3 border-t border-slate-200 bg-slate-50 px-6 py-4">
              <button
                onClick={handleReset}
                className="flex-1 rounded-lg border border-slate-300 px-4 py-2 font-semibold text-slate-700 transition-colors hover:bg-slate-100"
              >
                Scan Another
              </button>
              <button
                onClick={handleConfirm}
                className="flex-1 rounded-lg bg-gradient-to-r from-blue-500 to-indigo-500 px-4 py-2 font-semibold text-white shadow-md transition-all hover:from-blue-600 hover:to-indigo-600"
              >
                Review Complete, Add
              </button>
            </div>
          )}
        </motion.div>
      </div>
    </AnimatePresence>
  )
}

export default ReceiptScanner
