const readStoredOfflinePreference = (): boolean => {
  if (typeof window === 'undefined') return false

  try {
    return window.localStorage.getItem('anna_force_offline') === 'true'
  } catch {
    return false
  }
}

export const isOfflineOnlyMode = (): boolean => {
  return import.meta.env.VITE_FORCE_OFFLINE === 'true' || readStoredOfflinePreference()
}

export const isDeviceOnline = (): boolean => {
  if (typeof navigator === 'undefined') return false
  return !isOfflineOnlyMode() && navigator.onLine
}

export const getOfflineModeLabel = (): string => {
  return isOfflineOnlyMode() ? 'Offline-only mode' : 'Offline-first mode'
}
