// Enhanced AI Receipt Scanner (Server-Side)
// SECURITY: All AI provider calls are proxied through Firebase Functions.

import { httpsCallable } from 'firebase/functions'
import { functions } from './firebase'
import type { ScannedInvoiceData } from '../types'
import { getCurrentUserInfo } from '../utils/authUtils'
import { isDeviceOnline } from './runtimeMode'

const round2 = (value: unknown): number => {
  const numeric = Number(value)
  if (!Number.isFinite(numeric)) return 0
  return Math.round((numeric + Number.EPSILON) * 100) / 100
}

const readText = (value: unknown): string | undefined => {
  if (value === null || value === undefined) return undefined
  const text = String(value).replace(/\s+/g, ' ').trim()
  if (!text || ['n/a', 'na', 'nil', 'null', 'undefined', '-'].includes(text.toLowerCase())) {
    return undefined
  }
  return text
}

const readNumber = (value: unknown): number => {
  if (typeof value === 'number') return Number.isFinite(value) ? value : 0
  if (typeof value !== 'string') return 0
  const cleaned = value
    .replace(/[₹,\s]/g, '')
    .replace(/%/g, '')
    .replace(/[^\d.-]/g, '')
  const parsed = Number(cleaned)
  return Number.isFinite(parsed) ? parsed : 0
}

const normalizeDateText = (value: unknown): string | undefined => {
  const raw = readText(value)
  if (!raw) return undefined
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw
  if (/^\d{2}[-/]\d{2}$/.test(raw)) return raw.replace('/', '-')
  if (/^[A-Za-z]{3}[-/]\d{2,4}$/i.test(raw)) return raw.replace('/', '-').toUpperCase()

  const normalized = raw.replace(/[.]/g, '/').replace(/-/g, '/')
  const parts = normalized.split('/').map(part => part.trim()).filter(Boolean)
  if (parts.length === 3) {
    let [a, b, c] = parts
    if (c.length === 2) c = `20${c}`
    if (a.length === 4) {
      return `${a}-${b.padStart(2, '0')}-${c.padStart(2, '0')}`
    }
    return `${c.padStart(4, '0')}-${b.padStart(2, '0')}-${a.padStart(2, '0')}`
  }

  return raw
}

const looksLikeExpiryDate = (value: string | undefined): boolean => {
  if (!value) return false
  return (
    /^\d{4}-\d{2}-\d{2}$/.test(value) ||
    /^\d{2}[-/]\d{2}$/.test(value) ||
    /^\d{2}[-/]\d{2}[-/]\d{2,4}$/.test(value) ||
    /^[A-Za-z]{3}[-/]\d{2,4}$/i.test(value)
  )
}

const normalizeBatchText = (value: unknown): string | undefined => {
  const text = readText(value)
  if (!text) return undefined
  if (looksLikeExpiryDate(text)) return undefined
  return text
}

const normalizeExpiryValue = (value: unknown): string | undefined => {
  const normalized = normalizeDateText(value)
  if (!normalized) return undefined
  return looksLikeExpiryDate(normalized) ? normalized : undefined
}

const normalizeQuantityValue = (item: any): number => {
  const rawQuantity = round2(readNumber(
    item?.quantity ??
    item?.qty ??
    item?.qnty ??
    item?.qtyValue ??
    item?.qtyNos ??
    item?.qtyNo ??
    item?.quantityValue ??
    item?.pieces ??
    item?.units ??
    item?.q
  ) || 0)
  const rawRate = round2(readNumber(item?.rate))
  const rawAmount = round2(readNumber(item?.amount || item?.lineAmount || item?.total))
  let quantity = Math.max(1, rawQuantity || 1)

  if (rawRate > 0 && rawAmount > 0) {
    const exactQtyGuess = round2(rawAmount / rawRate)
    const roundedQtyGuess = Math.round(exactQtyGuess)
    const roundedAmountDelta = Math.abs(round2(rawRate * roundedQtyGuess) - rawAmount)

    if (rawQuantity <= 1 && roundedQtyGuess >= 2 && roundedAmountDelta <= Math.max(1, rawAmount * 0.05)) {
      quantity = roundedQtyGuess
    }
  }

  if (quantity > 0) {
    const nearestWhole = Math.round(quantity)
    if (Math.abs(quantity - nearestWhole) <= 0.2) {
      quantity = nearestWhole
    }
  }

  return round2(quantity)
}

const repairLineNumerics = (item: any) => {
  const rawQuantity = normalizeQuantityValue(item)
  const rawRate = round2(readNumber(item?.rate))
  const rawMrp = round2(readNumber(item?.mrp))
  const rawAmount = round2(readNumber(item?.amount || item?.lineAmount || item?.total))

  const qtyCandidates = Array.from(new Set([
    Math.max(1, Math.round(rawQuantity || 1)),
    rawRate > 0 && rawAmount > 0 ? Math.max(1, Math.round(rawAmount / rawRate)) : 0,
    rawMrp > 0 && rawAmount > 0 ? Math.max(1, Math.round(rawAmount / rawMrp)) : 0,
  ].filter(value => Number.isFinite(value) && value > 0)))

  const rateCandidates = Array.from(new Set([
    rawRate,
    rawMrp,
    rawQuantity > 0 && rawAmount > 0 ? round2(rawAmount / rawQuantity) : 0
  ].filter(value => Number.isFinite(value) && value > 0)))

  let best = {
    quantity: Math.max(1, rawQuantity || 1),
    rate: round2(rawRate || (rawMrp > 0 ? rawMrp : (rawAmount > 0 ? rawAmount / Math.max(1, rawQuantity || 1) : 0))),
    amount: rawAmount,
    error: rawAmount > 0 && rawRate > 0 ? Math.abs(round2(rawQuantity * rawRate) - rawAmount) : Number.POSITIVE_INFINITY,
    usedMrpAsRate: false
  }

  if (rawAmount > 0) {
    for (const qty of qtyCandidates) {
      for (const rate of rateCandidates) {
        const candidateAmount = round2(qty * rate)
        const error = Math.abs(candidateAmount - rawAmount)
        const usedMrpAsRate = rawMrp > 0 && Math.abs(rate - rawMrp) < 0.01
        const isBetter =
          error < best.error - 0.01 ||
          (Math.abs(error - best.error) <= 0.01 && usedMrpAsRate && !best.usedMrpAsRate)
        if (isBetter) {
          best = {
            quantity: qty,
            rate,
            amount: candidateAmount,
            error,
            usedMrpAsRate
          }
        }
      }
    }
  }

  const repairedQty = best.error <= Math.max(1, rawAmount * 0.05) ? best.quantity : Math.max(1, rawQuantity || 1)
  const repairedRate = best.error <= Math.max(1, rawAmount * 0.05)
    ? best.rate
    : round2(rawRate || (rawMrp > 0 ? rawMrp : (rawAmount > 0 ? rawAmount / Math.max(1, rawQuantity || 1) : 0)))
  const repairedMrp = round2(
    rawMrp > 0 && Math.abs(repairedRate - rawMrp) < 0.01 && rawRate > 0
      ? rawRate
      : rawMrp > 0
        ? rawMrp
        : repairedRate
  )
  const repairedAmount = rawAmount > 0 ? rawAmount : round2(repairedQty * repairedRate)

  return {
    quantity: repairedQty,
    rate: repairedRate,
    mrp: repairedMrp,
    amount: repairedAmount
  }
}

const isLikelyTaxRate = (value: number): boolean => {
  const standardRates = [0, 3, 5, 12, 18, 28]
  return standardRates.some(rate => Math.abs(value - rate) <= 0.2)
}

const normalizeHsnCode = (value: unknown): string | undefined => {
  const text = readText(value)
  if (!text) return undefined
  const compact = text.replace(/\s+/g, '')
  if (!/^\d{4,8}$/.test(compact)) return undefined
  return compact
}

const isNoiseRowDescription = (value: unknown): boolean => {
  const text = readText(value)
  if (!text) return true
  const normalized = text.toLowerCase()
  const noisePatterns = [
    'stock available',
    'sales value',
    'tot item',
    'tot.item',
    'bill amount',
    'rupees',
    'subject to',
    'round off',
    'discount @',
    'partner',
    'bank details',
    'pharmaceuticals'
  ]
  return noisePatterns.some(pattern => normalized.includes(pattern))
}

const pickFirstText = (...values: Array<unknown>): string | undefined => {
  for (const value of values) {
    const text = readText(value)
    if (text) return text
  }
  return undefined
}

const pickFirstNumber = (...values: Array<unknown>): number | undefined => {
  for (const value of values) {
    const numeric = round2(readNumber(value))
    if (numeric !== 0) return numeric
  }
  return undefined
}

const getItemSignature = (item: ScannedInvoiceData['items'][number]): string => {
  const description = readText(item?.description)?.toLowerCase() || ''
  const batchNo = readText(item?.batchNo)?.toLowerCase() || ''
  const amount = round2(item?.amount).toFixed(2)
  return `${description}|${batchNo}|${amount}`
}

const dedupeItems = (items: ScannedInvoiceData['items']): ScannedInvoiceData['items'] => {
  const seen = new Set<string>()
  return items.filter(item => {
    const signature = getItemSignature(item)
    if (seen.has(signature)) return false
    seen.add(signature)
    return true
  })
}

const getOverlapRatio = (baseItems: ScannedInvoiceData['items'], candidateItems: ScannedInvoiceData['items']): number => {
  if (!baseItems.length || !candidateItems.length) return 0
  const baseSignatures = new Set(baseItems.map(getItemSignature))
  const overlapCount = candidateItems.reduce(
    (count, item) => count + (baseSignatures.has(getItemSignature(item)) ? 1 : 0),
    0
  )
  return overlapCount / Math.max(1, candidateItems.length)
}

const resolveItemTaxableBase = (item: ScannedInvoiceData['items'][number]) => {
  const quantity = round2(item.quantity || 0)
  const rate = round2(item.rate || 0)
  const amount = round2(item.amount || 0)
  const explicitTaxable = round2(item.taxableValue || 0)
  const qtyRateBase = round2(quantity * rate)

  if (amount > 0 && qtyRateBase > 0 && Math.abs(amount - qtyRateBase) <= Math.max(2, amount * 0.03)) {
    return amount
  }

  if (amount > 0 && explicitTaxable > 0 && Math.abs(amount - explicitTaxable) <= Math.max(2, amount * 0.03)) {
    return amount
  }

  if (amount > 0 && explicitTaxable > amount * 1.15) {
    return amount
  }

  if (qtyRateBase > 0 && explicitTaxable > qtyRateBase * 1.15) {
    return qtyRateBase
  }

  return explicitTaxable || amount || qtyRateBase
}

const computeTaxFromRates = (items: ScannedInvoiceData['items']) => {
  return items.reduce((totals, item) => {
    const taxableBase = resolveItemTaxableBase(item)
    const gstRate = round2(item.gstRate || 0)
    const explicitIgst = round2(item.igstAmount || 0)

    if (taxableBase <= 0 || gstRate <= 0) {
      return totals
    }

    const lineTax = round2((taxableBase * gstRate) / 100)
    totals.total += lineTax

    if (explicitIgst > 0) {
      totals.igst += lineTax
      return totals
    }

    const halfTax = round2(lineTax / 2)
    totals.cgst += halfTax
    totals.sgst += round2(lineTax - halfTax)
    return totals
  }, {
    total: 0,
    cgst: 0,
    sgst: 0,
    igst: 0
  })
}

const normalizeScannedInvoiceData = (raw: any): ScannedInvoiceData => {
      const items = Array.isArray(raw?.items)
    ? raw.items
      .map((item: any) => {
        const repaired = repairLineNumerics(item)
        const quantity = repaired.quantity
        const rawRate = repaired.rate
        const rawAmount = repaired.amount

        const rate = round2(rawRate || (rawAmount > 0 ? rawAmount / quantity : 0))
        const lineAmount = round2(rawAmount || (rate * quantity))
        const lineTaxable = round2(item?.taxableValue ?? lineAmount)
        const lineCgstAmount = round2(readNumber(item?.cgstAmount || item?.cgst))
        const lineSgstAmount = round2(readNumber(item?.sgstAmount || item?.sgst))
        const lineIgstAmount = round2(readNumber(item?.igstAmount || item?.igst))
        const explicitDiscountAmount = round2(readNumber(item?.discountAmount))
        const lineDiscountPercent = round2(
          readNumber(item?.discountPercent || item?.discPercent || item?.disPercent || item?.discount || item?.disc) ||
          ((lineTaxable + explicitDiscountAmount) > 0
            ? (explicitDiscountAmount / (lineTaxable + explicitDiscountAmount)) * 100
            : 0)
        )
        const lineDiscountAmount = explicitDiscountAmount || round2((rate * quantity) * (lineDiscountPercent / 100))
        const explicitGstAmount = round2(
          readNumber(
            item?.gstAmount ||
            item?.taxAmount ||
            item?.taxValue ||
            item?.gst
          )
        )
        const lineGstAmount = round2(
          explicitGstAmount ||
          (lineCgstAmount + lineSgstAmount + lineIgstAmount)
        )
        const lineGstRate = round2(
          readNumber(item?.gstRate || item?.taxPercent || item?.gstPercent) ||
          (lineTaxable > 0 ? (lineGstAmount / lineTaxable) * 100 : 0)
        )
        const normalizedGstRate = (!isLikelyTaxRate(lineGstRate) && lineGstRate > 0 && lineGstAmount === 0)
          ? 0
          : lineGstRate
        const normalizedGstAmount = (!isLikelyTaxRate(lineGstRate) && lineGstRate > 0 && lineGstAmount === 0)
          ? lineGstRate
          : lineGstAmount

        const description = String(readText(item?.description || item?.itemName || item?.name) || 'Item')
        const normalizedItem = {
          description: String(readText(item?.description || item?.itemName || item?.name) || 'Item'),
          manufacturer: readText(
            item?.manufacturer ||
            item?.mfr ||
            item?.mfg ||
            item?.manufacturerName ||
            item?.maker ||
            item?.brandManufacturer
          ),
          batchNo: normalizeBatchText(
            item?.batchNo ||
            item?.batch ||
            item?.batchNoText ||
            item?.batchCode ||
            item?.bno ||
            item?.bNo ||
            item?.batch_no ||
            item?.batchno ||
            item?.batchNumber ||
            item?.batch_number ||
            item?.lot
          ),
          expiryDate: normalizeExpiryValue(
            item?.expiryDate ||
            item?.expDate ||
            item?.expdate ||
            item?.expDt ||
            item?.expdt ||
            item?.exDate ||
            item?.expiry ||
            item?.exdt ||
            item?.exDt ||
            item?.exp ||
            item?.expiry_date
          ),
          packageType: readText(item?.packageType || item?.pkg || item?.pack),
          hsnCode: normalizeHsnCode(item?.hsnCode || item?.hsn || item?.hsnSac),
          quantity,
          unit: String(readText(item?.unit || item?.uom || item?.packageType) || 'PCS'),
          rate,
          mrp: repaired.mrp,
          discountPercent: lineDiscountPercent,
          discountAmount: lineDiscountAmount,
          taxableValue: lineTaxable,
          gstRate: normalizedGstRate,
          gstAmount: normalizedGstAmount,
          cgstAmount: lineCgstAmount,
          sgstAmount: lineSgstAmount,
          igstAmount: lineIgstAmount,
          amount: lineAmount
        }
        return isNoiseRowDescription(description) ? null : normalizedItem
      })
      .filter(Boolean) as ScannedInvoiceData['items']
    : []

  const computedSubtotal = round2(
    items.reduce((sum, item) => sum + ((item.rate || 0) * (item.quantity || 0)), 0)
  )
  const computedTaxable = round2(
    items.reduce((sum, item) => sum + (item.taxableValue || item.amount || 0), 0)
  )
  const computedCgstAmount = round2(items.reduce((sum, item) => sum + round2(item.cgstAmount), 0))
  const computedSgstAmount = round2(items.reduce((sum, item) => sum + round2(item.sgstAmount), 0))
  const computedIgstAmount = round2(items.reduce((sum, item) => sum + round2(item.igstAmount), 0))
  const computedTaxFromRates = computeTaxFromRates(items)

  const subtotal = round2(
    (() => {
      const rawSubtotal = round2(readNumber(raw?.subtotal))
      if (rawSubtotal > 0 && computedSubtotal > 0 && Math.abs(rawSubtotal - computedSubtotal) <= computedSubtotal * 0.4) {
        return rawSubtotal
      }
      return computedSubtotal
    })()
  )
  const taxableValue = round2(
    (() => {
      const rawTaxable = round2(readNumber(raw?.taxableValue))
      if (rawTaxable > 0 && computedTaxable > 0 && Math.abs(rawTaxable - computedTaxable) <= computedTaxable * 0.4) {
        return rawTaxable
      }
      return computedTaxable
    })()
  )
  const explicitCgstAmount = round2(readNumber(raw?.cgstAmount))
  const explicitSgstAmount = round2(readNumber(raw?.sgstAmount))
  const explicitIgstAmount = round2(readNumber(raw?.igstAmount))
  const explicitTaxAmount = round2(
    readNumber(raw?.totalTaxAmount) ||
    readNumber(raw?.gstAmount) ||
    (explicitCgstAmount + explicitSgstAmount + explicitIgstAmount)
  )
  const roundOff = round2(raw?.roundOff || 0)
  const explicitDiscountAmount = round2(readNumber(raw?.discountAmount || raw?.discount))
  const rawGrandTotal = round2(readNumber(raw?.grandTotal || raw?.billAmount))
  const directGrandWithExplicitDiscount = subtotal > 0 && explicitDiscountAmount > 0
    ? round2(subtotal - explicitDiscountAmount + explicitTaxAmount + roundOff)
    : 0
  const subtotalMathReliable =
    subtotal > 0 &&
    (
      computedTaxable <= 0 ||
      Math.abs(subtotal - computedTaxable) <= Math.max(2, subtotal * 0.08)
    )
  const explicitDiscountLooksValid =
    explicitDiscountAmount > 0 &&
    rawGrandTotal > 0 &&
    directGrandWithExplicitDiscount > 0 &&
    Math.abs(rawGrandTotal - directGrandWithExplicitDiscount) <= Math.max(2, rawGrandTotal * 0.03)
  const discountAmount = round2(
    explicitDiscountLooksValid
      ? explicitDiscountAmount
      : 0
  )
  const trustedTaxableValue = subtotalMathReliable
    ? round2(Math.max(0, subtotal - discountAmount))
    : taxableValue
  const computedTaxFromRows = round2(computedCgstAmount + computedSgstAmount + computedIgstAmount)
  const computedTaxFromRatesTotal = round2(computedTaxFromRates.total)
  const rateTaxLooksReasonable =
    computedTaxFromRatesTotal > 0 &&
    (
      computedTaxFromRows <= 0 ||
      Math.abs(computedTaxFromRatesTotal - computedTaxFromRows) > Math.max(5, computedTaxFromRatesTotal * 0.3)
    )
  const explicitTaxLooksSuspicious =
    explicitTaxAmount > 0 &&
    computedTaxFromRatesTotal > 0 &&
    Math.abs(explicitTaxAmount - computedTaxFromRatesTotal) >= Math.max(8, computedTaxFromRatesTotal * 0.25)
  const explicitTaxLooksReasonable =
    explicitTaxAmount > 0 &&
    (
      computedTaxFromRatesTotal <= 0 ||
      Math.abs(explicitTaxAmount - computedTaxFromRatesTotal) <= Math.max(5, computedTaxFromRatesTotal * 0.2)
    )
  const totalTaxAmount = round2(
    explicitTaxLooksReasonable
      ? explicitTaxAmount
      : explicitTaxLooksSuspicious
        ? computedTaxFromRatesTotal
      : rateTaxLooksReasonable
        ? computedTaxFromRatesTotal
        : (explicitTaxAmount || computedTaxFromRows || computedTaxFromRatesTotal)
  )
  const cgstAmount = round2(
    explicitTaxLooksReasonable
      ? explicitCgstAmount
      : explicitTaxLooksSuspicious
        ? computedTaxFromRates.cgst
      : rateTaxLooksReasonable
        ? computedTaxFromRates.cgst
        : (explicitCgstAmount || computedCgstAmount || computedTaxFromRates.cgst)
  )
  const sgstAmount = round2(
    explicitTaxLooksReasonable
      ? explicitSgstAmount
      : explicitTaxLooksSuspicious
        ? computedTaxFromRates.sgst
      : rateTaxLooksReasonable
        ? computedTaxFromRates.sgst
        : (explicitSgstAmount || computedSgstAmount || computedTaxFromRates.sgst)
  )
  const igstAmount = round2(
    explicitTaxLooksReasonable
      ? explicitIgstAmount
      : explicitTaxLooksSuspicious
        ? computedTaxFromRates.igst
      : rateTaxLooksReasonable
        ? computedTaxFromRates.igst
        : (explicitIgstAmount || computedIgstAmount || computedTaxFromRates.igst)
  )
  const computedGrandTotal = round2(trustedTaxableValue + totalTaxAmount + roundOff)
  const grandTotal = round2(
    rawGrandTotal > 0 && Math.abs(rawGrandTotal - computedGrandTotal) <= Math.max(2, computedGrandTotal * 0.03)
      ? rawGrandTotal
      : computedGrandTotal
  )
  const baseBeforeDiscount = round2(trustedTaxableValue + discountAmount)
  const discountPercent = round2(
    raw?.discountPercent ??
    (baseBeforeDiscount > 0 ? (discountAmount / baseBeforeDiscount) * 100 : 0)
  )

  return {
    vendor: {
      name: String(raw?.vendor?.name || 'Unknown Vendor'),
      address: raw?.vendor?.address ? String(raw.vendor.address) : undefined,
      city: raw?.vendor?.city ? String(raw.vendor.city) : undefined,
      state: raw?.vendor?.state ? String(raw.vendor.state) : undefined,
      pinCode: raw?.vendor?.pinCode ? String(raw.vendor.pinCode) : undefined,
      gstin: raw?.vendor?.gstin ? String(raw.vendor.gstin) : undefined,
      stateCode: raw?.vendor?.stateCode ? String(raw.vendor.stateCode) : undefined,
      phone: readText(raw?.vendor?.phone),
      email: readText(raw?.vendor?.email)
    },
    buyer: raw?.buyer ? {
      name: String(raw?.buyer?.name || ''),
      address: readText(raw?.buyer?.address),
      city: readText(raw?.buyer?.city),
      state: readText(raw?.buyer?.state),
      pinCode: readText(raw?.buyer?.pinCode),
      gstin: readText(raw?.buyer?.gstin),
      stateCode: readText(raw?.buyer?.stateCode),
      phone: readText(raw?.buyer?.phone),
      email: readText(raw?.buyer?.email)
    } : undefined,
    invoiceNumber: String(raw?.invoiceNumber || ''),
    invoiceDate: String(raw?.invoiceDate || new Date().toISOString().split('T')[0]),
    deliveryNoteNumber: raw?.deliveryNoteNumber ? String(raw.deliveryNoteNumber) : undefined,
    referenceNumber: raw?.referenceNumber ? String(raw.referenceNumber) : undefined,
    buyerOrderNumber: raw?.buyerOrderNumber ? String(raw.buyerOrderNumber) : undefined,
    dispatchDocNumber: raw?.dispatchDocNumber ? String(raw.dispatchDocNumber) : undefined,
    deliveryNoteDate: raw?.deliveryNoteDate ? String(raw.deliveryNoteDate) : undefined,
    vehicleNumber: raw?.vehicleNumber ? String(raw.vehicleNumber) : undefined,
    destination: raw?.destination ? String(raw.destination) : undefined,
    items,
    subtotal,
    taxableValue: trustedTaxableValue,
    cgstRate: round2(raw?.cgstRate || 0),
    cgstAmount,
    sgstRate: round2(raw?.sgstRate || 0),
    sgstAmount,
    igstRate: round2(raw?.igstRate || 0),
    igstAmount,
    totalTaxAmount,
    discountPercent,
    discountAmount,
    roundOff,
    grandTotal,
    paymentMode: raw?.paymentMode ? String(raw.paymentMode) : undefined,
    termsOfPayment: raw?.termsOfPayment ? String(raw.termsOfPayment) : undefined
  }
}

const ensureFunctionsReady = () => {
  if (!functions) {
    throw new Error('Firebase functions not initialized')
  }
}

const createOfflineScanPlaceholder = (file: File): ScannedInvoiceData => {
  const inferredInvoiceNumber = file.name
    .replace(/\.[^.]+$/, '')
    .replace(/[_-]+/g, ' ')
    .trim()

  return {
    vendor: {
      name: 'Manual Review Required'
    },
    buyer: undefined,
    invoiceNumber: inferredInvoiceNumber,
    invoiceDate: new Date().toISOString().split('T')[0],
    vehicleNumber: '',
    items: [],
    subtotal: 0,
    taxableValue: 0,
    cgstRate: 0,
    cgstAmount: 0,
    sgstRate: 0,
    sgstAmount: 0,
    igstRate: 0,
    igstAmount: 0,
    totalTaxAmount: 0,
    discountPercent: 0,
    discountAmount: 0,
    roundOff: 0,
    grandTotal: 0,
    termsOfPayment: 'Cloud receipt scanning unavailable. Please review and enter details manually.'
  }
}

const isAdminAIUser = (): boolean => {
  // Receipt scanning is enforced server-side. Keep the client permissive so
  // valid signed-in users are not blocked by stale/partial local role data.
  const info = getCurrentUserInfo()
  return !!info?.uid
}

const MAX_UPLOAD_BYTES = 2 * 1024 * 1024 // Must match Cloud Function limits

const readFileAsDataUrl = (file: File): Promise<string> =>
  new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(String(reader.result || ''))
    reader.onerror = () => reject(new Error('Failed to read file'))
    reader.readAsDataURL(file)
  })

const dataUrlToBase64 = (dataUrl: string): { base64: string; mimeType: string } => {
  const match = dataUrl.match(/^data:([^;]+);base64,(.*)$/)
  if (!match) {
    // Fallback: attempt to split at comma
    const parts = dataUrl.split(',')
    return { base64: parts[1] || dataUrl, mimeType: 'image/jpeg' }
  }
  return { mimeType: match[1], base64: match[2] }
}

const estimateBase64Bytes = (base64: string): number => {
  // Approx bytes for base64 payload.
  const len = base64.length
  const padding = base64.endsWith('==') ? 2 : base64.endsWith('=') ? 1 : 0
  return Math.floor((len * 3) / 4) - padding
}

const loadImage = (dataUrl: string): Promise<HTMLImageElement> =>
  new Promise((resolve, reject) => {
    const img = new Image()
    img.onload = () => resolve(img)
    img.onerror = () => reject(new Error('Failed to load image'))
    img.src = dataUrl
  })

const canvasToJpegBlob = (canvas: HTMLCanvasElement, quality: number): Promise<Blob> =>
  new Promise((resolve, reject) => {
    canvas.toBlob(
      blob => {
        if (!blob) {
          reject(new Error('Failed to encode image'))
          return
        }
        resolve(blob)
      },
      'image/jpeg',
      quality
    )
  })

const enhanceReceiptCanvas = (canvas: HTMLCanvasElement) => {
  const ctx = canvas.getContext('2d', { willReadFrequently: true })
  if (!ctx) return

  const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height)
  const data = imageData.data
  const grayscale = new Float32Array(canvas.width * canvas.height)

  let minLuma = 255
  let maxLuma = 0
  for (let i = 0, p = 0; i < data.length; i += 4, p += 1) {
    const luma = 0.299 * data[i] + 0.587 * data[i + 1] + 0.114 * data[i + 2]
    grayscale[p] = luma
    if (luma < minLuma) minLuma = luma
    if (luma > maxLuma) maxLuma = luma
  }

  const range = Math.max(1, maxLuma - minLuma)
  const sharpened = new Float32Array(grayscale.length)

  for (let y = 0; y < canvas.height; y += 1) {
    for (let x = 0; x < canvas.width; x += 1) {
      const idx = y * canvas.width + x
      const center = grayscale[idx]
      const left = x > 0 ? grayscale[idx - 1] : center
      const right = x < canvas.width - 1 ? grayscale[idx + 1] : center
      const up = y > 0 ? grayscale[idx - canvas.width] : center
      const down = y < canvas.height - 1 ? grayscale[idx + canvas.width] : center

      const normalized = ((center - minLuma) / range) * 255
      const sharpenValue = normalized * 1.7 - (left + right + up + down) * 0.175
      sharpened[idx] = Math.max(0, Math.min(255, sharpenValue))
    }
  }

  for (let i = 0, p = 0; i < data.length; i += 4, p += 1) {
    const value = sharpened[p]
    data[i] = value
    data[i + 1] = value
    data[i + 2] = value
  }

  ctx.putImageData(imageData, 0, 0)
}

async function prepareImageForFunction(file: File): Promise<{ base64: string; mimeType: string }> {
  console.log('[prepareImageForFunction] Starting for file:', file.name)
  const originalDataUrl = await readFileAsDataUrl(file)
  console.log('[prepareImageForFunction] DataURL length:', originalDataUrl.length)
  
  const original = dataUrlToBase64(originalDataUrl)
  console.log('[prepareImageForFunction] Original converted:', {
    base64Length: original.base64.length,
    estimatedBytes: estimateBase64Bytes(original.base64),
    mimeType: original.mimeType,
  })

  if (estimateBase64Bytes(original.base64) <= MAX_UPLOAD_BYTES) {
    console.log('[prepareImageForFunction] Original size OK, returning as-is')
    return original
  }

  console.log('[prepareImageForFunction] Original too large, compressing...')

  // Compress on the client to stay within callable payload limits.
  const img = await loadImage(originalDataUrl)
  console.log('[prepareImageForFunction] Image loaded:', { width: img.width, height: img.height })
  
  // Dense pharmacy invoices lose table readability quickly when over-compressed.
  const maxDim = 1800
  const scale = Math.min(1, maxDim / Math.max(img.width, img.height))
  const width = Math.max(1, Math.round(img.width * scale))
  const height = Math.max(1, Math.round(img.height * scale))

  const canvas = document.createElement('canvas')
  canvas.width = width
  canvas.height = height
  const ctx = canvas.getContext('2d')
  if (!ctx) {
    throw new Error('Canvas not supported')
  }
  ctx.drawImage(img, 0, 0, width, height)
  enhanceReceiptCanvas(canvas)
  console.log('[prepareImageForFunction] Canvas created:', { width, height })

  // Try a few quality levels.
  const qualities = [0.92, 0.85, 0.75, 0.65, 0.55]
  for (const q of qualities) {
    console.log(`[prepareImageForFunction] Trying quality: ${q}`)
    const blob = await canvasToJpegBlob(canvas, q)
    const dataUrl = await readFileAsDataUrl(new File([blob], 'receipt.jpg', { type: 'image/jpeg' }))
    const converted = dataUrlToBase64(dataUrl)
    const estimatedBytes = estimateBase64Bytes(converted.base64)
    console.log(`[prepareImageForFunction] Quality ${q}:`, {
      base64Length: converted.base64.length,
      estimatedBytes,
      isBelowLimit: estimatedBytes <= MAX_UPLOAD_BYTES,
    })
    if (estimatedBytes <= MAX_UPLOAD_BYTES) {
      console.log(`[prepareImageForFunction] Quality ${q} passed, returning`)
      return converted
    }
  }

  throw new Error('Image too large. Please upload a smaller image.')
}

const mergeInvoicePartials = (scans: ScannedInvoiceData[]): ScannedInvoiceData => {
  if (!scans.length) {
    throw new Error('No scanned invoice pages to merge.')
  }

  const first = scans[0]
  const primaryItemsScan = scans.reduce((best, scan) => {
    const bestCount = best.items?.length || 0
    const scanCount = scan.items?.length || 0
    return scanCount > bestCount ? scan : best
  }, first)
  const primaryItems = primaryItemsScan.items || []

  const items = dedupeItems(
    scans.flatMap(scan => {
      const scanItems = scan.items || []
      if (!scanItems.length) return []
      const overlapRatio = getOverlapRatio(primaryItems, scanItems)
      const looksLikeDuplicateSummaryPage =
        scan !== primaryItemsScan &&
        primaryItems.length > 0 &&
        overlapRatio >= 0.8

      return looksLikeDuplicateSummaryPage ? [] : scanItems
    })
  )

  const getSummaryStrength = (scan: ScannedInvoiceData) => {
    let score = 0
    if (round2(scan.discountAmount) > 0) score += 50
    if (round2(scan.roundOff) !== 0) score += 20
    if (round2(scan.totalTaxAmount) > 0) score += 20
    if (round2(scan.grandTotal) > 0) score += 20
    if (round2(scan.subtotal) > 0) score += 10
    if ((scan.items?.length || 0) === 0) score += 10
    return score
  }

  const summaryScan = scans.reduce((best, scan) => {
    const bestScore = getSummaryStrength(best)
    const scanScore = getSummaryStrength(scan)
    if (scanScore !== bestScore) return scanScore > bestScore ? scan : best

    const bestTotal = round2(best.grandTotal || best.subtotal || 0)
    const scanTotal = round2(scan.grandTotal || scan.subtotal || 0)
    return scanTotal > bestTotal ? scan : best
  }, first)

  const subtotal = round2(
    round2(summaryScan.subtotal) ||
    items.reduce((sum, item) => sum + round2((item.rate || 0) * (item.quantity || 0)), 0)
  )
  const computedMergedTaxable = round2(
    items.reduce((sum, item) => sum + round2(item.taxableValue || item.amount || 0), 0)
  )
  const mergedTaxFromRows = {
    cgst: round2(items.reduce((sum, item) => sum + round2(item.cgstAmount), 0)),
    sgst: round2(items.reduce((sum, item) => sum + round2(item.sgstAmount), 0)),
    igst: round2(items.reduce((sum, item) => sum + round2(item.igstAmount), 0)),
  }
  const mergedTaxFromRates = computeTaxFromRates(items)
  const mergedExplicitTax = round2(
    round2(summaryScan.totalTaxAmount) ||
    (
      round2(summaryScan.cgstAmount) +
      round2(summaryScan.sgstAmount) +
      round2(summaryScan.igstAmount)
    )
  )
  const mergedRateTaxLooksReasonable =
    mergedTaxFromRates.total > 0 &&
    (
      (mergedTaxFromRows.cgst + mergedTaxFromRows.sgst + mergedTaxFromRows.igst) <= 0 ||
      Math.abs(mergedTaxFromRates.total - (mergedTaxFromRows.cgst + mergedTaxFromRows.sgst + mergedTaxFromRows.igst)) >
        Math.max(5, mergedTaxFromRates.total * 0.3)
    )
  const mergedExplicitTaxLooksSuspicious =
    mergedExplicitTax > 0 &&
    mergedTaxFromRates.total > 0 &&
    Math.abs(mergedExplicitTax - mergedTaxFromRates.total) >= Math.max(8, mergedTaxFromRates.total * 0.25)
  const mergedExplicitTaxLooksReasonable =
    mergedExplicitTax > 0 &&
    (
      mergedTaxFromRates.total <= 0 ||
      Math.abs(mergedExplicitTax - mergedTaxFromRates.total) <= Math.max(5, mergedTaxFromRates.total * 0.2)
    )
  const totalTaxAmount = round2(
    mergedExplicitTaxLooksReasonable
      ? mergedExplicitTax
      : mergedExplicitTaxLooksSuspicious
        ? mergedTaxFromRates.total
      : mergedRateTaxLooksReasonable
        ? mergedTaxFromRates.total
        : (mergedExplicitTax || mergedTaxFromRows.cgst + mergedTaxFromRows.sgst + mergedTaxFromRows.igst || mergedTaxFromRates.total)
  )
  const cgstAmount = round2(
    mergedExplicitTaxLooksReasonable
      ? round2(summaryScan.cgstAmount)
      : mergedExplicitTaxLooksSuspicious
        ? mergedTaxFromRates.cgst
      : mergedRateTaxLooksReasonable
        ? mergedTaxFromRates.cgst
        : (round2(summaryScan.cgstAmount) || mergedTaxFromRows.cgst || mergedTaxFromRates.cgst)
  )
  const sgstAmount = round2(
    mergedExplicitTaxLooksReasonable
      ? round2(summaryScan.sgstAmount)
      : mergedExplicitTaxLooksSuspicious
        ? mergedTaxFromRates.sgst
      : mergedRateTaxLooksReasonable
        ? mergedTaxFromRates.sgst
        : (round2(summaryScan.sgstAmount) || mergedTaxFromRows.sgst || mergedTaxFromRates.sgst)
  )
  const igstAmount = round2(
    mergedExplicitTaxLooksReasonable
      ? round2(summaryScan.igstAmount)
      : mergedExplicitTaxLooksSuspicious
        ? mergedTaxFromRates.igst
      : mergedRateTaxLooksReasonable
        ? mergedTaxFromRates.igst
        : (round2(summaryScan.igstAmount) || mergedTaxFromRows.igst || mergedTaxFromRates.igst)
  )
  const discountAmount = round2(round2(summaryScan.discountAmount) || 0)
  const roundOff = round2(round2(summaryScan.roundOff) || 0)
  const explicitSummaryTaxable = round2(round2(summaryScan.taxableValue) || 0)
  const subtotalMathReliable =
    subtotal > 0 &&
    (
      computedMergedTaxable <= 0 ||
      Math.abs(subtotal - computedMergedTaxable) <= Math.max(2, subtotal * 0.08)
    )
  const taxableValue = round2(
    explicitSummaryTaxable > 0
      ? explicitSummaryTaxable
      : subtotalMathReliable
      ? Math.max(0, subtotal - discountAmount)
      : (round2(summaryScan.taxableValue) || computedMergedTaxable)
  )
  const grandTotal = round2(
    (
      round2(summaryScan.grandTotal) > 0 &&
      Math.abs(round2(summaryScan.grandTotal) - (taxableValue + totalTaxAmount + roundOff)) <= Math.max(2, (taxableValue + totalTaxAmount + roundOff) * 0.03)
    )
      ? round2(summaryScan.grandTotal)
      : (taxableValue + totalTaxAmount + roundOff)
  )
  const baseBeforeDiscount = round2(taxableValue + discountAmount)
  const discountPercent = round2(
    baseBeforeDiscount > 0 ? (discountAmount / baseBeforeDiscount) * 100 : 0
  )

  return {
    vendor: {
      name: pickFirstText(...scans.map(scan => scan.vendor?.name)) || first.vendor?.name || 'Unknown Vendor',
      address: pickFirstText(...scans.map(scan => scan.vendor?.address)),
      city: pickFirstText(...scans.map(scan => scan.vendor?.city)),
      state: pickFirstText(...scans.map(scan => scan.vendor?.state)),
      pinCode: pickFirstText(...scans.map(scan => scan.vendor?.pinCode)),
      gstin: pickFirstText(...scans.map(scan => scan.vendor?.gstin)),
      stateCode: pickFirstText(...scans.map(scan => scan.vendor?.stateCode)),
      phone: pickFirstText(...scans.map(scan => scan.vendor?.phone)),
      email: pickFirstText(...scans.map(scan => scan.vendor?.email))
    },
    buyer: scans.some(scan => scan.buyer?.name)
      ? {
          name: pickFirstText(...scans.map(scan => scan.buyer?.name)) || '',
          address: pickFirstText(...scans.map(scan => scan.buyer?.address)),
          city: pickFirstText(...scans.map(scan => scan.buyer?.city)),
          state: pickFirstText(...scans.map(scan => scan.buyer?.state)),
          pinCode: pickFirstText(...scans.map(scan => scan.buyer?.pinCode)),
          gstin: pickFirstText(...scans.map(scan => scan.buyer?.gstin)),
          stateCode: pickFirstText(...scans.map(scan => scan.buyer?.stateCode)),
          phone: pickFirstText(...scans.map(scan => scan.buyer?.phone)),
          email: pickFirstText(...scans.map(scan => scan.buyer?.email))
        }
      : undefined,
    invoiceNumber: pickFirstText(...scans.map(scan => scan.invoiceNumber)) || '',
    invoiceDate: pickFirstText(...scans.map(scan => scan.invoiceDate)) || first.invoiceDate,
    deliveryNoteNumber: pickFirstText(...scans.map(scan => scan.deliveryNoteNumber)),
    referenceNumber: pickFirstText(...scans.map(scan => scan.referenceNumber)),
    buyerOrderNumber: pickFirstText(...scans.map(scan => scan.buyerOrderNumber)),
    dispatchDocNumber: pickFirstText(...scans.map(scan => scan.dispatchDocNumber)),
    deliveryNoteDate: pickFirstText(...scans.map(scan => scan.deliveryNoteDate)),
    vehicleNumber: pickFirstText(...scans.map(scan => scan.vehicleNumber)),
    destination: pickFirstText(...scans.map(scan => scan.destination)),
    items,
    subtotal,
    taxableValue,
    cgstRate: pickFirstNumber(...scans.map(scan => scan.cgstRate)) || 0,
    cgstAmount,
    sgstRate: pickFirstNumber(...scans.map(scan => scan.sgstRate)) || 0,
    sgstAmount,
    igstRate: pickFirstNumber(...scans.map(scan => scan.igstRate)) || 0,
    igstAmount,
    totalTaxAmount,
    discountPercent,
    discountAmount,
    roundOff,
    grandTotal,
    paymentMode: pickFirstText(...scans.map(scan => scan.paymentMode)),
    termsOfPayment: pickFirstText(...scans.map(scan => scan.termsOfPayment))
  }
}

export async function scanCompleteInvoice(imageFile: File): Promise<ScannedInvoiceData> {
  if (!functions || !isDeviceOnline()) {
    return createOfflineScanPlaceholder(imageFile)
  }

  ensureFunctionsReady()

  console.log('[scanCompleteInvoice] Starting with file:', {
    name: imageFile.name,
    type: imageFile.type,
    size: imageFile.size,
  })

  const { base64, mimeType } = await prepareImageForFunction(imageFile)
  console.log('[scanCompleteInvoice] Image prepared:', {
    base64Length: base64.length,
    base64Bytes: estimateBase64Bytes(base64),
    mimeType,
    maxBytes: MAX_UPLOAD_BYTES,
  })

  if (!base64) {
    throw new Error('Image preparation failed: empty base64 string.')
  }

  if (estimateBase64Bytes(base64) > MAX_UPLOAD_BYTES) {
    throw new Error('Image too large. Please upload a smaller image.')
  }

  const payload = { imageBase64: base64, mimeType }
  console.log('[scanCompleteInvoice] Payload created:', {
    hasImageBase64: !!payload.imageBase64,
    imageBase64Length: payload.imageBase64?.length || 0,
    mimeType: payload.mimeType,
    payloadKeys: Object.keys(payload),
    imageBase64Preview: payload.imageBase64?.substring(0, 100) || 'MISSING'
  })

  const callable = httpsCallable(functions!, 'aiReceiptScan', {
    timeout: 540000,
  })
  console.log('[scanCompleteInvoice] httpsCallable created, about to invoke with payload')
  console.log('[scanCompleteInvoice] Calling with:', JSON.stringify({
    hasImageBase64: !!payload.imageBase64,
    imageBase64Length: payload.imageBase64?.length,
    mimeType: payload.mimeType
  }))

  try {
    const response = await callable(payload)
    console.log('[scanCompleteInvoice] Response received:', response.data)
    return normalizeScannedInvoiceData(response.data)
  } catch (error: any) {
    console.error('[scanCompleteInvoice] Function call failed:', {
      code: error?.code,
      message: error?.message,
      details: error?.details,
      errorType: error?.constructor?.name
    })
    throw error
  }
}

export async function scanCompleteInvoiceFiles(imageFiles: File[]): Promise<ScannedInvoiceData> {
  const files = imageFiles.filter(Boolean)
  if (!files.length) {
    throw new Error('Please upload at least one invoice image.')
  }

  if (files.length === 1) {
    return scanCompleteInvoice(files[0])
  }

  const scans: ScannedInvoiceData[] = []
  for (const file of files) {
    scans.push(await scanCompleteInvoice(file))
  }

  return mergeInvoicePartials(scans)
}
